import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

export async function GET(
    req: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const { id } = await params

        const project = await prisma.projects.findUnique({
            where: { id },
            include: {
                workspaces: {
                    include: { cards: true },
                },
                conversations: true,
            },
        })

        if (!project) {
            return new Response('Project not found', { status: 404 })
        }

        return NextResponse.json(project)
    } catch (error) {
        console.error('Fetch project error:', error)
        return new Response('Internal Server Error', { status: 500 })
    }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

export async function PATCH(
    req: NextRequest,
    { params }: { params: Promise<{ cardId: string }> }
) {
    try {
        const { cardId } = await params
        const body = await req.json()
        const { x, y } = body

        if (typeof x !== 'number' || typeof y !== 'number') {
            return new Response('Invalid position data', { status: 400 })
        }

        const updatedCard = await prisma.cards.update({
            where: { id: cardId },
            data: { position: { x, y } },
        })

        return NextResponse.json({ success: true, data: updatedCard })
    } catch (error) {
        console.error('Update position error:', error)
        return new Response('Internal Server Error', { status: 500 })
    }
}

import { NextResponse } from 'next/server'
import { searchReddit, analyzeRedditSentiment } from '@/lib/external/reddit-api'

export async function POST(req: Request) {
    try {
        const { query } = await req.json()

        if (!query) {
            return NextResponse.json({ error: 'Query required' }, { status: 400 })
        }

        const posts = await searchReddit(query)
        const analysis = analyzeRedditSentiment(posts)

        return NextResponse.json({
            posts: posts.slice(0, 5), // Limit to top 5 to save tokens
            analysis
        })

    } catch (error: any) {
        return NextResponse.json({ error: error.message }, { status: 500 })
    }
}

