        await verifyProjectOwnership(id, user.id)

        const project = await prisma.projects.findUnique({
            where: { id },
            include: {
                workspaces: {
                    include: { cards: true },
                },
                conversations: true,
            },
        })

        if (!project) {
            return new Response('Project not found', { status: 404 })
